72: // loader is a wrapper structure around operations related to compiling,
73: // loading, and reloading datapath programs.
74: type loader struct {
75: 	// templateCache is the cache of pre-compiled datapaths. Only set after
76: 	// a call to Reinitialize.
77: 	templateCache *objectCache
78: 
79: 	ipsecMu lock.Mutex // guards reinitializeIPSec
80: 
81: 	hostDpInitializedOnce sync.Once
82: 	hostDpInitialized     chan struct{}
83: 
84: 	sysctl          sysctl.Sysctl
85: 	prefilter       datapath.PreFilter
86: 	compilationLock datapath.CompilationLock
87: 	configWriter    datapath.ConfigWriter
88: 	nodeHandler     datapath.NodeHandler
89: }
90: 
91: type Params struct {
92: 	cell.In
93: 
94: 	Sysctl          sysctl.Sysctl
95: 	Prefilter       datapath.PreFilter
96: 	CompilationLock datapath.CompilationLock
97: 	ConfigWriter    datapath.ConfigWriter
98: 	NodeHandler     datapath.NodeHandler
99: 
100: 	// Force map initialisation before loader. You should not use these otherwise.
101: 	// Some of the entries in this slice may be nil.
102: 	BpfMaps []bpf.BpfMap `group:"bpf-maps"`
103: }
