105: // newLoader returns a new loader.
106: func newLoader(p Params) *loader {
107: 	return &loader{
108: 		templateCache:     newObjectCache(p.ConfigWriter, filepath.Join(option.Config.StateDir, defaults.TemplatesDir)),
109: 		sysctl:            p.Sysctl,
110: 		hostDpInitialized: make(chan struct{}),
111: 		prefilter:         p.Prefilter,
112: 		compilationLock:   p.CompilationLock,
113: 		configWriter:      p.ConfigWriter,
114: 		nodeHandler:       p.NodeHandler,
115: 	}
116: }
