118: func upsertEndpointRoute(ep datapath.Endpoint, ip net.IPNet) error {
119: 	endpointRoute := route.Route{
120: 		Prefix: ip,
121: 		Device: ep.InterfaceName(),
122: 		Scope:  netlink.SCOPE_LINK,
123: 		Proto:  linux_defaults.RTProto,
124: 	}
125: 
126: 	return route.Upsert(endpointRoute)
127: }
