129: func removeEndpointRoute(ep datapath.Endpoint, ip net.IPNet) error {
130: 	return route.Delete(route.Route{
131: 		Prefix: ip,
132: 		Device: ep.InterfaceName(),
133: 		Scope:  netlink.SCOPE_LINK,
134: 	})
135: }
