244: // removeObsoleteNetdevPrograms removes cil_to_netdev and cil_from_netdev from devices
245: // that cilium potentially doesn't manage anymore after a restart, e.g. if the set of
246: // devices changes between restarts.
247: //
248: // This code assumes that the agent was upgraded from a prior version while maintaining
249: // the same list of managed physical devices. This ensures that all tc bpf filters get
250: // replaced using the naming convention of the 'current' agent build. For example,
251: // before 1.13, most filters were named e.g. bpf_host.o:[to-host], to be changed to
252: // cilium-<device> in 1.13, then to cil_to_host-<device> in 1.14. As a result, this
253: // function only cleans up filters following the current naming scheme.
254: func removeObsoleteNetdevPrograms(devices []string) error {
255: 	links, err := safenetlink.LinkList()
256: 	if err != nil {
257: 		return fmt.Errorf("retrieving all netlink devices: %w", err)
258: 	}
259: 
260: 	// collect all devices that have netdev programs attached on either ingress or egress.
261: 	ingressDevs := []netlink.Link{}
262: 	egressDevs := []netlink.Link{}
263: 	for _, l := range links {
264: 		if !isObsoleteDev(l.Attrs().Name, devices) {
265: 			continue
266: 		}
267: 
268: 		// Remove the per-device bpffs directory containing pinned links and
269: 		// per-endpoint maps.
270: 		bpffsPath := bpffsDeviceDir(bpf.CiliumPath(), l)
271: 		if err := bpf.Remove(bpffsPath); err != nil {
272: 			log.WithError(err).WithField(logfields.Device, l.Attrs().Name)
273: 		}
274: 
275: 		ingressFilters, err := safenetlink.FilterList(l, directionToParent(dirIngress))
276: 		if err != nil {
277: 			return fmt.Errorf("listing ingress filters: %w", err)
278: 		}
279: 		for _, filter := range ingressFilters {
280: 			if bpfFilter, ok := filter.(*netlink.BpfFilter); ok {
281: 				if strings.HasPrefix(bpfFilter.Name, symbolFromHostNetdevEp) {
282: 					ingressDevs = append(ingressDevs, l)
283: 				}
284: 			}
285: 		}
286: 
287: 		egressFilters, err := safenetlink.FilterList(l, directionToParent(dirEgress))
288: 		if err != nil {
289: 			return fmt.Errorf("listing egress filters: %w", err)
290: 		}
291: 		for _, filter := range egressFilters {
292: 			if bpfFilter, ok := filter.(*netlink.BpfFilter); ok {
293: 				if strings.HasPrefix(bpfFilter.Name, symbolToHostNetdevEp) {
294: 					egressDevs = append(egressDevs, l)
295: 				}
296: 			}
297: 		}
298: 	}
299: 
300: 	for _, dev := range ingressDevs {
301: 		err = removeTCFilters(dev, directionToParent(dirIngress))
302: 		if err != nil {
303: 			log.WithError(err).Errorf("couldn't remove ingress tc filters from %s", dev.Attrs().Name)
304: 		}
305: 	}
306: 
307: 	for _, dev := range egressDevs {
308: 		err = removeTCFilters(dev, directionToParent(dirEgress))
309: 		if err != nil {
310: 			log.WithError(err).Errorf("couldn't remove egress tc filters from %s", dev.Attrs().Name)
311: 		}
312: 	}
313: 
314: 	return nil
315: }
