336: // attachCiliumHost inserts the host endpoint's policy program into the global
337: // cilium_call_policy map and attaches programs from bpf_host.c to cilium_host.
338: func attachCiliumHost(ep datapath.Endpoint, spec *ebpf.CollectionSpec) error {
339: 	host, err := safenetlink.LinkByName(ep.InterfaceName())
340: 	if err != nil {
341: 		return fmt.Errorf("retrieving device %s: %w", ep.InterfaceName(), err)
342: 	}
343: 
344: 	var hostObj hostObjects
345: 	commit, err := bpf.LoadAndAssign(&hostObj, spec, &bpf.CollectionOptions{
346: 		CollectionOptions: ebpf.CollectionOptions{
347: 			Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
348: 		},
349: 		MapRenames: ELFMapSubstitutions(ep),
350: 		Constants:  ELFVariableSubstitutions(ep),
351: 	})
352: 	if err != nil {
353: 		return err
354: 	}
355: 	defer hostObj.Close()
356: 
357: 	// Insert host endpoint policy program.
358: 	if err := hostObj.PolicyMap.Update(uint32(ep.GetID()), hostObj.PolicyProg, ebpf.UpdateAny); err != nil {
359: 		return fmt.Errorf("inserting host endpoint policy program: %w", err)
360: 	}
361: 
362: 	// Attach cil_to_host to cilium_host ingress.
363: 	if err := attachSKBProgram(host, hostObj.ToHost, symbolToHostEp,
364: 		bpffsDeviceLinksDir(bpf.CiliumPath(), host), netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
365: 		return fmt.Errorf("interface %s ingress: %w", ep.InterfaceName(), err)
366: 	}
367: 	// Attach cil_from_host to cilium_host egress.
368: 	if err := attachSKBProgram(host, hostObj.FromHost, symbolFromHostEp,
369: 		bpffsDeviceLinksDir(bpf.CiliumPath(), host), netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
370: 		return fmt.Errorf("interface %s egress: %w", ep.InterfaceName(), err)
371: 	}
372: 
373: 	if err := commit(); err != nil {
374: 		return fmt.Errorf("committing bpf pins: %w", err)
375: 	}
376: 
377: 	return nil
378: }
