418: // attachNetworkDevices attaches programs from bpf_host.c to externally-facing
419: // devices and the wireguard device. Attaches cil_from_netdev to ingress and
420: // optionally cil_to_netdev to egress if enabled features require it.
421: func attachNetworkDevices(cfg *datapath.LocalNodeConfiguration, ep datapath.Endpoint, spec *ebpf.CollectionSpec) error {
422: 	devices := cfg.DeviceNames()
423: 
424: 	// Selectively attach bpf_host to cilium_wg0.
425: 	if option.Config.NeedBPFHostOnWireGuardDevice() {
426: 		devices = append(devices, wgTypes.IfaceName)
427: 	}
428: 
429: 	// Replace programs on physical devices, ignoring devices that don't exist.
430: 	for _, device := range devices {
431: 		iface, err := safenetlink.LinkByName(device)
432: 		if err != nil {
433: 			log.WithError(err).WithField("device", device).Warn("Link does not exist")
434: 			continue
435: 		}
436: 
437: 		linkDir := bpffsDeviceLinksDir(bpf.CiliumPath(), iface)
438: 
439: 		consts, renames, err := hostRewrites(cfg, ep, device)
440: 		if err != nil {
441: 			return err
442: 		}
443: 
444: 		var netdevObj hostNetdevObjects
445: 		commit, err := bpf.LoadAndAssign(&netdevObj, spec, &bpf.CollectionOptions{
446: 			CollectionOptions: ebpf.CollectionOptions{
447: 				Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
448: 			},
449: 			MapRenames: renames,
450: 			Constants:  consts,
451: 		})
452: 		if err != nil {
453: 			return err
454: 		}
455: 		defer netdevObj.Close()
456: 
457: 		// Attach cil_from_netdev to ingress.
458: 		if err := attachSKBProgram(iface, netdevObj.FromNetdev, symbolFromHostNetdevEp,
459: 			linkDir, netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
460: 			return fmt.Errorf("interface %s ingress: %w", device, err)
461: 		}
462: 
463: 		// When downgrading from v1.18, upon successfully attaching cil_from_netdev
464: 		// to cilium_wg0, we must remove the cil_from_wireguard program.
465: 		if device == wgTypes.IfaceName {
466: 			if err := detachSKBProgram(iface, symbolFromWireguard,
467: 				linkDir, netlink.HANDLE_MIN_INGRESS); err != nil {
468: 				log.WithField("device", device).Error(err)
469: 			}
470: 			// Cleanup also calls map from v1.18 after downgrade.
471: 			cleanCallsMaps(fmt.Sprintf("cilium_calls_wireguard_%d", iface.Attrs().Index))
472: 		}
473: 
474: 		if option.Config.AreDevicesRequired() {
475: 			// Attaching bpf_host to cilium_wg0 is required for encrypting KPR
476: 			// traffic. Only ingress prog (aka "from-netdev") is needed to handle
477: 			// the rev-NAT xlations.
478: 			if device != wgTypes.IfaceName {
479: 				// Attach cil_to_netdev to egress.
480: 				if err := attachSKBProgram(iface, netdevObj.ToNetdev, symbolToHostNetdevEp,
481: 					linkDir, netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
482: 					return fmt.Errorf("interface %s egress: %w", device, err)
483: 				}
484: 			}
485: 		} else {
486: 			// Remove any previously attached device from egress path if BPF
487: 			// NodePort and host firewall are disabled.
488: 			if err := detachSKBProgram(iface, symbolToHostNetdevEp, linkDir, netlink.HANDLE_MIN_EGRESS); err != nil {
489: 				log.WithField("device", device).Error(err)
490: 			}
491: 		}
492: 
493: 		if err := commit(); err != nil {
494: 			return fmt.Errorf("committing bpf pins: %w", err)
495: 		}
496: 	}
497: 
498: 	// Call immediately after attaching programs to make it obvious that a
499: 	// program was wrongfully detached due to a bug or misconfiguration.
500: 	if err := removeObsoleteNetdevPrograms(devices); err != nil {
501: 		log.WithError(err).Error("Failed to remove obsolete netdev programs")
502: 	}
503: 
504: 	return nil
505: }
