507: // reloadEndpoint loads programs in spec into the device used by ep.
508: //
509: // spec is modified by the method and it is the callers responsibility to copy
510: // it if necessary.
511: func reloadEndpoint(ep datapath.Endpoint, spec *ebpf.CollectionSpec) error {
512: 	device := ep.InterfaceName()
513: 
514: 	var obj lxcObjects
515: 	commit, err := bpf.LoadAndAssign(&obj, spec, &bpf.CollectionOptions{
516: 		CollectionOptions: ebpf.CollectionOptions{
517: 			Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
518: 		},
519: 		MapRenames: ELFMapSubstitutions(ep),
520: 		Constants:  ELFVariableSubstitutions(ep),
521: 	})
522: 	if err != nil {
523: 		return err
524: 	}
525: 	defer obj.Close()
526: 
527: 	// Insert policy programs before attaching entrypoints to tc hooks.
528: 	// Inserting a policy program is considered an attachment, since it makes
529: 	// the code reachable by bpf_host when it evaluates policy for the endpoint.
530: 	// All internal tail call plumbing needs to be done before this point.
531: 	// If the agent dies uncleanly after the first program has been inserted,
532: 	// the endpoint's connectivity will be partially broken or exhibit undefined
533: 	// behaviour like missed tail calls or drops.
534: 	if err := obj.PolicyMap.Update(uint32(ep.GetID()), obj.PolicyProg, ebpf.UpdateAny); err != nil {
535: 		return fmt.Errorf("inserting endpoint policy program: %w", err)
536: 	}
537: 	if err := obj.EgressPolicyMap.Update(uint32(ep.GetID()), obj.EgressPolicyProg, ebpf.UpdateAny); err != nil {
538: 		return fmt.Errorf("inserting endpoint egress policy program: %w", err)
539: 	}
540: 
541: 	iface, err := safenetlink.LinkByName(device)
542: 	if err != nil {
543: 		return fmt.Errorf("retrieving device %s: %w", device, err)
544: 	}
545: 
546: 	linkDir := bpffsEndpointLinksDir(bpf.CiliumPath(), ep)
547: 	if err := attachSKBProgram(iface, obj.FromContainer, symbolFromEndpoint,
548: 		linkDir, netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
549: 		return fmt.Errorf("interface %s ingress: %w", device, err)
550: 	}
551: 
552: 	if ep.RequireEgressProg() {
553: 		if err := attachSKBProgram(iface, obj.ToContainer, symbolToEndpoint,
554: 			linkDir, netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
555: 			return fmt.Errorf("interface %s egress: %w", device, err)
556: 		}
557: 	} else {
558: 		if err := detachSKBProgram(iface, symbolToEndpoint, linkDir, netlink.HANDLE_MIN_EGRESS); err != nil {
559: 			log.WithField("device", device).Error(err)
560: 		}
561: 	}
562: 
563: 	if err := commit(); err != nil {
564: 		return fmt.Errorf("committing bpf pins: %w", err)
565: 	}
566: 
567: 	if ep.RequireEndpointRoute() {
568: 		scopedLog := ep.Logger(subsystem).WithFields(logrus.Fields{
569: 			logfields.Interface: device,
570: 		})
571: 		if ip := ep.IPv4Address(); ip.IsValid() {
572: 			if err := upsertEndpointRoute(ep, *netipx.AddrIPNet(ip)); err != nil {
573: 				scopedLog.WithError(err).Warn("Failed to upsert route")
574: 			}
575: 		}
576: 		if ip := ep.IPv6Address(); ip.IsValid() {
577: 			if err := upsertEndpointRoute(ep, *netipx.AddrIPNet(ip)); err != nil {
578: 				scopedLog.WithError(err).Warn("Failed to upsert route")
579: 			}
580: 		}
581: 	}
582: 
583: 	return nil
584: }
