142: func cleanIngressQdisc(devices []string) error {
143: 	for _, iface := range devices {
144: 		link, err := safenetlink.LinkByName(iface)
145: 		if err != nil {
146: 			return fmt.Errorf("failed to retrieve link %s by name: %w", iface, err)
147: 		}
148: 		qdiscs, err := safenetlink.QdiscList(link)
149: 		if err != nil {
150: 			return fmt.Errorf("failed to retrieve qdisc list of link %s: %w", iface, err)
151: 		}
152: 		for _, q := range qdiscs {
153: 			if q.Type() != "ingress" {
154: 				continue
155: 			}
156: 			err = netlink.QdiscDel(q)
157: 			if err != nil {
158: 				return fmt.Errorf("failed to delete ingress qdisc of link %s: %w", iface, err)
159: 			} else {
160: 				log.WithField(logfields.Device, iface).Info("Removed prior present ingress qdisc from device so that Cilium's datapath can be loaded")
161: 			}
162: 		}
163: 	}
164: 	return nil
165: }
