305: func reinitializeWireguard(ctx context.Context) (err error) {
306: 	if !option.Config.EnableWireguard {
307: 		cleanCallsMaps("cilium_calls_wireguard*")
308: 		return
309: 	}
310: 
311: 	link, err := safenetlink.LinkByName(wgTypes.IfaceName)
312: 	if err != nil {
313: 		return fmt.Errorf("failed to retrieve link for interface %s: %w", wgTypes.IfaceName, err)
314: 	}
315: 
316: 	opts := []string{
317: 		fmt.Sprintf("-DSECLABEL=%d", identity.ReservedIdentityWorld),
318: 		fmt.Sprintf("-DTHIS_INTERFACE_MAC={.addr=%s}", mac.CArrayString(link.Attrs().HardwareAddr)),
319: 		fmt.Sprintf("-DCALLS_MAP=cilium_calls_wireguard_%d", identity.ReservedIdentityWorld),
320: 	}
