358: // ReinitializeXDP (re-)configures the XDP datapath only. This includes recompilation
359: // and reinsertion of the object into the kernel as well as an atomic program replacement
360: // at the XDP hook. extraCArgs can be passed-in in order to alter BPF code defines.
361: func (l *loader) ReinitializeXDP(ctx context.Context, cfg *datapath.LocalNodeConfiguration, extraCArgs []string) error {
362: 	l.compilationLock.Lock()
363: 	defer l.compilationLock.Unlock()
364: 	devices := cfg.DeviceNames()
365: 
366: 	return reinitializeXDPLocked(ctx, extraCArgs, devices, cfg.XDPConfig)
367: }
