378: // Reinitialize (re-)configures the base datapath configuration including global
379: // BPF programs, netfilter rule configuration and reserving routes in IPAM for
380: // locally detected prefixes. It may be run upon initial Cilium startup, after
381: // restore from a previous Cilium run, or during regular Cilium operation.
382: func (l *loader) Reinitialize(ctx context.Context, cfg *datapath.LocalNodeConfiguration, tunnelConfig tunnel.Config, iptMgr datapath.IptablesManager, p datapath.Proxy) error {
383: 	sysSettings := []tables.Sysctl{
384: 		{Name: []string{"net", "core", "bpf_jit_enable"}, Val: "1", IgnoreErr: true, Warn: "Unable to ensure that BPF JIT compilation is enabled. This can be ignored when Cilium is running inside non-host network namespace (e.g. with kind or minikube)"},
385: 		{Name: []string{"net", "ipv4", "conf", "all", "rp_filter"}, Val: "0", IgnoreErr: false},
386: 		{Name: []string{"net", "ipv4", "fib_multipath_use_neigh"}, Val: "1", IgnoreErr: true},
387: 		{Name: []string{"kernel", "unprivileged_bpf_disabled"}, Val: "1", IgnoreErr: true},
388: 		{Name: []string{"kernel", "timer_migration"}, Val: "0", IgnoreErr: true},
389: 	}
390: 
391: 	// Lock so that endpoints cannot be built while we are compile base programs.
392: 	l.compilationLock.Lock()
393: 	defer l.compilationLock.Unlock()
394: 
395: 	// Startup relies on not returning an error here, maybe something we
396: 	// can fix in the future.
397: 	_ = l.templateCache.UpdateDatapathHash(cfg)
398: 
399: 	var internalIPv4, internalIPv6 net.IP
400: 	if option.Config.EnableIPv4 {
401: 		internalIPv4 = cfg.CiliumInternalIPv4
402: 	}
403: 	if option.Config.EnableIPv6 {
404: 		internalIPv6 = cfg.CiliumInternalIPv6
405: 		// Docker <17.05 has an issue which causes IPv6 to be disabled in the initns for all
406: 		// interface (https://github.com/docker/libnetwork/issues/1720)
407: 		// Enable IPv6 for now
408: 		sysSettings = append(sysSettings,
409: 			tables.Sysctl{Name: []string{"net", "ipv6", "conf", "all", "disable_ipv6"}, Val: "0", IgnoreErr: false})
410: 	}
411: 
412: 	// BPF file system setup.
413: 	if err := bpf.MkdirBPF(bpf.TCGlobalsPath()); err != nil {
414: 		return fmt.Errorf("failed to create bpffs directory: %w", err)
415: 	}
416: 
417: 	// Datapath initialization
418: 	hostDev1, _, err := setupBaseDevice(l.sysctl, cfg.DeviceMTU)
419: 	if err != nil {
420: 		return fmt.Errorf("failed to setup base devices: %w", err)
421: 	}
422: 
423: 	if option.Config.EnableHealthDatapath || option.Config.EnableIPIPTermination {
424: 		// This setting needs to be applied before creating the IPIP devices.
425: 		sysIPIP := []tables.Sysctl{
426: 			{Name: []string{"net", "core", "fb_tunnels_only_for_init_net"}, Val: "2", IgnoreErr: true},
427: 		}
428: 		if err := l.sysctl.ApplySettings(sysIPIP); err != nil {
429: 			return err
430: 		}
431: 		if err := setupIPIPDevices(l.sysctl, option.Config.IPv4Enabled(), option.Config.IPv6Enabled(), cfg.DeviceMTU); err != nil {
432: 			return fmt.Errorf("unable to create ipip devices: %w", err)
433: 		}
434: 	}
435: 
436: 	if err := setupTunnelDevice(l.sysctl, tunnelConfig.Protocol(), tunnelConfig.Port(),
437: 		tunnelConfig.SrcPortLow(), tunnelConfig.SrcPortHigh(), cfg.DeviceMTU); err != nil {
438: 		return fmt.Errorf("failed to setup %s tunnel device: %w", tunnelConfig.Protocol(), err)
439: 	}
440: 
441: 	if option.Config.IPAM == ipamOption.IPAMENI {
442: 		var err error
443: 		if sysSettings, err = addENIRules(sysSettings); err != nil {
444: 			return fmt.Errorf("unable to install ip rule for ENI multi-node NodePort: %w", err)
445: 		}
446: 	}
447: 
448: 	// Any code that relies on sysctl settings being applied needs to be called after this.
449: 	if err := l.sysctl.ApplySettings(sysSettings); err != nil {
450: 		return err
451: 	}
452: 
453: 	// add internal ipv4 and ipv6 addresses to cilium_host
454: 	if err := addHostDeviceAddr(hostDev1, internalIPv4, internalIPv6); err != nil {
455: 		return fmt.Errorf("failed to add internal IP address to %s: %w", hostDev1.Attrs().Name, err)
456: 	}
457: 
458: 	devices := cfg.DeviceNames()
459: 
460: 	if err := cleanIngressQdisc(devices); err != nil {
461: 		log.WithError(err).Warn("Unable to clean up ingress qdiscs")
462: 		return err
463: 	}
464: 
465: 	if err := l.writeNodeConfigHeader(cfg); err != nil {
466: 		log.WithError(err).Error("Unable to write node config header")
467: 		return err
468: 	}
469: 
470: 	if err := l.writeNetdevHeader("./"); err != nil {
471: 		log.WithError(err).Warn("Unable to write netdev header")
472: 		return err
473: 	}
474: 
475: 	if option.Config.EnableXDPPrefilter {
476: 		scopedLog := log.WithField(logfields.Devices, devices)
477: 
478: 		if err := writePreFilterHeader(l.prefilter, "./", devices); err != nil {
479: 			scopedLog.WithError(err).Warn("Unable to write prefilter header")
480: 			return err
481: 		}
482: 	}
483: 
484: 	ctx, cancel := context.WithTimeout(ctx, defaults.ExecTimeout)
485: 	defer cancel()
486: 
487: 	if option.Config.EnableSocketLB {
488: 		// compile bpf_sock.c and attach/detach progs for socketLB
489: 		if err := compileWithOptions(ctx, "bpf_sock.c", "bpf_sock.o", []string{"-DCALLS_MAP=cilium_calls_lb"}); err != nil {
490: 			log.WithError(err).Fatal("failed to compile bpf_sock.c")
491: 		}
492: 		if err := socketlb.Enable(l.sysctl); err != nil {
493: 			return err
494: 		}
495: 	} else {
496: 		if err := socketlb.Disable(); err != nil {
497: 			return err
498: 		}
499: 	}
500: 
501: 	extraArgs := []string{"-Dcapture_enabled=0"}
502: 	if err := reinitializeXDPLocked(ctx, extraArgs, devices, cfg.XDPConfig); err != nil {
503: 		log.WithError(err).Fatal("Failed to compile XDP program")
504: 	}
505: 
506: 	// Compile alignchecker program
507: 	if err := compileDefault(ctx, "bpf_alignchecker.c", defaults.AlignCheckerName); err != nil {
508: 		log.WithError(err).Fatal("alignchecker compile failed")
509: 	}
510: 	// Validate alignments of C and Go equivalent structs
511: 	alignchecker.RegisterLbStructsToCheck(option.Config.LoadBalancerAlgorithmAnnotation)
512: 	if err := alignchecker.CheckStructAlignments(defaults.AlignCheckerName); err != nil {
513: 		log.WithError(err).Fatal("C and Go structs alignment check failed")
514: 	}
515: 
516: 	if option.Config.EnableIPSec {
517: 		if err := compileNetwork(ctx); err != nil {
518: 			log.WithError(err).Fatal("failed to compile encryption programs")
519: 		}
520: 
521: 		if err := l.reinitializeIPSec(); err != nil {
522: 			return err
523: 		}
524: 	}
525: 
526: 	if err := reinitializeOverlay(ctx, tunnelConfig); err != nil {
527: 		return err
528: 	}
529: 
530: 	if err := reinitializeWireguard(ctx); err != nil {
531: 		return err
532: 	}
533: 
534: 	if err := l.nodeHandler.NodeConfigurationChanged(*cfg); err != nil {
535: 		return err
536: 	}
537: 
538: 	// Reinstall proxy rules for any running proxies if needed
539: 	if option.Config.EnableL7Proxy {
540: 		if err := p.ReinstallRoutingRules(cfg.RouteMTU); err != nil {
541: 			return err
542: 		}
543: 	}
544: 
545: 	return nil
546: }
